import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"Notes","description":"","frontmatter":{},"headers":[],"relativePath":"guide/notes.md","filePath":"guide/notes.md","lastUpdated":1771855656000}'),r={name:"guide/notes.md"};function i(s,e,d,l,h,p){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h1><p>Notes let you record anything that happened on a particular date that might affect your lab results or help you remember context later. They are completely independent of your lab entries — you do not need a blood draw on the same date to add a note.</p><h2 id="adding-a-note" tabindex="-1">Adding a Note <a class="header-anchor" href="#adding-a-note" aria-label="Permalink to &quot;Adding a Note&quot;">​</a></h2><p>Scroll to the <strong>Data &amp; Notes</strong> section at the bottom of the dashboard and click <strong>Add Note</strong>. Enter:</p><ul><li><strong>Date</strong> — the date the note applies to</li><li><strong>Text</strong> — what you want to remember</li></ul><p>Notes can be anything: starting a new medication, a period of high stress, an illness, a dietary change, a travel period, or a doctor&#39;s comment you want to keep alongside your data.</p><h2 id="notes-on-the-dashboard" tabindex="-1">Notes on the Dashboard <a class="header-anchor" href="#notes-on-the-dashboard" aria-label="Permalink to &quot;Notes on the Dashboard&quot;">​</a></h2><p>Notes appear interleaved with your lab entries in the chronological timeline, displayed with a <strong>yellow left border</strong> to distinguish them from lab data at a glance.</p><h2 id="yellow-dots-on-charts" tabindex="-1">Yellow Dots on Charts <a class="header-anchor" href="#yellow-dots-on-charts" aria-label="Permalink to &quot;Yellow Dots on Charts&quot;">​</a></h2><p>Open the <strong>Layers</strong> dropdown in the chart area and enable <strong>Notes</strong> to show a <strong>yellow dot</strong> on every chart at each date where you have a note. Hovering over a dot shows the note text as a tooltip.</p><p>This lets you visually correlate events with changes in your biomarkers. For example, you might see that a spike in CRP lines up with a note about an infection, or that your testosterone dipped during the week you noted extreme work stress.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The note overlay is off by default. Turn it on in the Layers dropdown whenever you want to see how events correlated with your trends.</p></div><h2 id="notes-in-the-detail-modal" tabindex="-1">Notes in the Detail Modal <a class="header-anchor" href="#notes-in-the-detail-modal" aria-label="Permalink to &quot;Notes in the Detail Modal&quot;">​</a></h2><p>When you open the detail view for a specific marker, any notes from dates that appear on that chart are shown alongside the data — marked with a memo icon. This keeps relevant context visible without leaving the detail view.</p><h2 id="notes-in-ai-context" tabindex="-1">Notes in AI Context <a class="header-anchor" href="#notes-in-ai-context" aria-label="Permalink to &quot;Notes in AI Context&quot;">​</a></h2><p>All your notes are included when the AI builds context for the chat panel or for per-marker explanations. The AI can reference your notes directly — for example, explaining a CRP elevation in the context of a note you wrote about a cold that week.</p><h2 id="editing-and-deleting-notes" tabindex="-1">Editing and Deleting Notes <a class="header-anchor" href="#editing-and-deleting-notes" aria-label="Permalink to &quot;Editing and Deleting Notes&quot;">​</a></h2><p>Click any note in the dashboard list to edit its text or date. Use the delete button to remove it. Deleting a note removes its dot from all charts immediately.</p><h2 id="export-and-import" tabindex="-1">Export and Import <a class="header-anchor" href="#export-and-import" aria-label="Permalink to &quot;Export and Import&quot;">​</a></h2><p>Notes are included in your JSON export. When you import a file, duplicate notes (same date and text) are automatically removed.</p>',20)])])}const m=t(r,[["render",i]]);export{u as __pageData,m as default};
